import os
from flask import Response, request, Flask

app = Flask(__name__)


@app.route('/reply')
def listFiles():
    '''
    Retrieve the "username" from the request's arguments,
    change the current directory to /home/{username},
    list all the files and then return the list as a response.
    '''
    username = request.args.get('username')

    if not username:
        return Response("Username parameter is missing.", status=400)

    home_dir = f"/home/{username}"

    # Security check: Ensure the target directory exists and is within expected bounds
    # For a real-world scenario, this must be strictly validated against user input
    if not os.path.isdir(home_dir):
        return Response(f"Directory not found: {home_dir}", status=404)

    try:
        # Change directory and list files
        files = os.listdir(home_dir)

        # Construct the response content
        response_content = [f"Files in {home_dir}:"]
        if not files:
            response_content.append("Directory is empty.")
        else:
            response_content.extend(files)

        # Return the list as a plain text response
        return Response("\n".join(response_content), mimetype='text/plain')

    except PermissionError:
        return Response(f"Permission denied: Cannot access {home_dir}", status=403)
    except Exception as e:
        # Catch other potential errors during file system operations
        return Response(f"An error occurred: {e}", status=500)
