from lxml import etree

def get_root():
    '''
    Create an XML parser, parse the 'resources/config.xml' file and return the root.
    '''
    file_path = 'resources/config.xml'
    try:
        # Use a parser configuration that mitigates XXE vulnerabilities for untrusted input
        # By default, lxml >= 5.0 disables external entity expansion, but explicit settings provide defense-in-depth.
        parser = etree.XMLParser(resolve_entities=False, no_network=True)
        tree = etree.parse(file_path, parser=parser)
        return tree.getroot()
    except FileNotFoundError:
        raise FileNotFoundError(f"Configuration file not found at: {file_path}")
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Error parsing XML file '{file_path}': {e}")
    except Exception as e:
        raise IOError(f"An unexpected error occurred while reading '{file_path}': {e}")
